#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long a1,a2,a3,a4,a5,p; scanf("%lld %lld %lld %lld %lld %lld", &a1,&a2,&a3,&a4,&a5,&p);
        long long sum = a1+a2+a3+a4+a5;
        if(sum * p > 120) printf("Yes\n"); else printf("No\n");
    }
    return 0;
}

