code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            long a1 = Long.parseLong(st.nextToken());
            long a2 = Long.parseLong(st.nextToken());
            long a3 = Long.parseLong(st.nextToken());
            long a4 = Long.parseLong(st.nextToken());
            long a5 = Long.parseLong(st.nextToken());
            long p = Long.parseLong(st.nextToken());
            long sum = a1 + a2 + a3 + a4 + a5;
            sb.append(sum * p > 120 ? "Yes" : "No").append('\n');
        }
        System.out.print(sb.toString());
    }
}

